`IFormFile` buffers the entire body into memory — that's the root cause. Instead, read the raw `Request.Body` stream (or use `MultipartReader`) and write chunks directly to disk.

Here's the streaming approach:

```csharp
using Microsoft.AspNetCore.Http.Features;
using Microsoft.AspNetCore.WebUtilities;
using Microsoft.Net.Http.Headers;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// 1. Raise the server-level max request size (Kestrel default is 30 MB)
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 2L * 1024 * 1024 * 1024); // 2 GB

app.MapPost("/upload", async (HttpContext ctx) =>
{
    // 2. Disable request body buffering — critical for true streaming
    ctx.Features.Get<IHttpRequestBodyDetectionFeature>();
    var request = ctx.Request;
    request.EnableBuffering(bufferThreshold: 1024 * 64); // optional small memory threshold

    // 3. Verify we have a multipart content type
    if (!request.HasFormContentType ||
        !MediaTypeHeaderValue.TryParse(request.ContentType, out var mt) ||
        !mt.MediaType.Equals("multipart/form-data", StringComparison.OrdinalIgnoreCase))
    {
        return Results.BadRequest("Expected multipart/form-data");
    }

    var boundary = HeaderUtilities.RemoveQuotes(mt.Boundary).Value;
    if (string.IsNullOrEmpty(boundary))
        return Results.BadRequest("Missing boundary");

    // 4. Read sections one at a time — never loads the whole file
    var reader = new MultipartReader(boundary, request.Body);
    MultipartSection? section;

    while ((section = await reader.ReadNextSectionAsync()) != null)
    {
        if (!ContentDispositionHeaderValue.TryParse(section.ContentDisposition, out var cd) ||
            !cd.IsFileDisposition())
        {
            continue; // skip non-file fields
        }

        var trustedName = Path.GetRandomFileName();          // never trust the client name
        var savePath = Path.Combine(Path.GetTempPath(), trustedName);

        // 5. Stream to disk in chunks — memory stays flat
        await using var fs = new FileStream(savePath, FileMode.Create);
        await section.Body.CopyToAsync(fs);

        return Results.Ok(new { saved = savePath, size = fs.Length });
    }

    return Results.BadRequest("No file section found");
})
.DisableAntiforgery();   // required for minimal-API form posts without tokens

app.Run();
```

**Key pieces that make this work:**

| Problem | Fix |
|---|---|
| Kestrel rejects >30 MB | `MaxRequestBodySize = 2GB` |
| `IFormFile` buffers to RAM | Use `MultipartReader` to stream sections |
| `Request.Form` also buffers | Never touch `Request.Form`; parse the boundary yourself |
| IIS/reverse-proxy limits | Also set `maxAllowedContentLength` in `web.config` if behind IIS |

**If behind IIS**, add to `web.config`:

```xml
<system.webServer>
  <security>
    <requestFiltering>
      <requestLimits maxAllowedContentLength="2147483648" />
    </requestFiltering>
  </security>
</system.webServer>
```

Memory stays flat at ~64 KB regardless of file size because `CopyToAsync` streams in small buffers internally.
